#[allow(clippy::redundant_closure, clippy::useless_conversion)]
impl From<WasmResponse> for spikard_http::Response {
    fn from(val: WasmResponse) -> Self {
        Self {
            content: val
                .content
                .as_ref()
                .and_then(|v| serde_wasm_bindgen::from_value(v.clone()).ok()),
            status_code: val.status_code,
            headers: serde_wasm_bindgen::from_value(val.headers.clone()).unwrap_or_default(),
        }
    }
}

#[allow(clippy::redundant_closure, clippy::useless_conversion)]
impl From<spikard_http::Response> for WasmResponse {
    fn from(val: spikard_http::Response) -> Self {
        Self {
            content: val.content.as_ref().and_then(|v| serde_wasm_bindgen::to_value(v).ok()),
            status_code: val.status_code,
            headers: serde_wasm_bindgen::to_value(&val.headers).unwrap_or(JsValue::NULL),
        }
    }
}

