impl From<spikard_http::Method> for WasmMethod {
    fn from(val: spikard_http::Method) -> Self {
        match val {
            spikard_http::Method::Get => Self::Get,
            spikard_http::Method::Post => Self::Post,
            spikard_http::Method::Put => Self::Put,
            spikard_http::Method::Patch => Self::Patch,
            spikard_http::Method::Delete => Self::Delete,
            spikard_http::Method::Head => Self::Head,
            spikard_http::Method::Options => Self::Options,
            spikard_http::Method::Trace => Self::Trace,
        }
    }
}

impl From<WasmSecuritySchemeInfo> for spikard_http::SecuritySchemeInfo {
    fn from(val: WasmSecuritySchemeInfo) -> Self {
        match val {
            WasmSecuritySchemeInfo::Http => Self::Http {
                scheme: Default::default(),
                bearer_format: Default::default(),
            },
            WasmSecuritySchemeInfo::ApiKey => Self::ApiKey {
                location: Default::default(),
                name: Default::default(),
            },
        }
    }
}

impl From<spikard_http::SecuritySchemeInfo> for WasmSecuritySchemeInfo {
    fn from(val: spikard_http::SecuritySchemeInfo) -> Self {
        match val {
            spikard_http::SecuritySchemeInfo::Http { .. } => Self::Http,
            spikard_http::SecuritySchemeInfo::ApiKey { .. } => Self::ApiKey,
        }
    }
}
